--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,29 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  let i = 0
+  while (i < argv.length) {
+    const arg = argv[i]
+    if (!arg.startsWith('-')) {
+      result._.push(arg)
+      i += 1
+      continue
+    }
+    if (arg.includes('=')) {
+      const eqIndex = arg.indexOf('=')
+      result[arg.slice(2, eqIndex)] = arg.slice(eqIndex + 1)
+      i += 1
+      continue
+    }
+    if (i + 1 < argv.length) {
+      const next = argv[i + 1]
+      if (!next.startsWith('-')) {
+        result[arg.slice(2)] = next
+        i += 2
+        continue
+      }
+    }
+    result[arg.slice(2)] = true
+    i += 1
   }
   return result
 }

